oxy_webhelp_navlinks = {"proxmox_protection_management-d30753e26177":{"topics":[{"title":"Creating a custom SLA Domain","shortdesc":"<p class=\"shortdesc\">Create a custom SLA Domain to streamline and customize workload protection and         management policies.<\/p>","href":"saas\/rsc_creating_custom_sla_domain_4.html","attributes":{"data-id":"rsc_creating_custom_sla_domain"},"menu":{"hasChildren":false},"tocID":"rsc_creating_custom_sla_domain-d30753e26190","topics":[]},{"title":"Creating SLA Domains for many-to-one replication","shortdesc":"<p class=\"shortdesc\">Create an SLA Domain for many-to-one replication, the traditional replication mode         supported by <span class=\"ph\">RSC<\/span> SLA Domains. This method consolidates data protection from         multiple source clusters onto a single target cluster, ensuring centralized recovery and         protection.<\/p>","href":"saas\/rsc_creating_sla_domains_manytoone_rep_2.html","attributes":{"data-id":"rsc_creating_sla_domains_manytoone_rep"},"menu":{"hasChildren":false},"tocID":"rsc_creating_sla_domains_manytoone_rep-d30753e26201","topics":[]},{"title":"Creating SLA Domains for one-to-one replication","shortdesc":"<p class=\"shortdesc\">Create an SLA Domain for one-to-one replication when there are more than two         replication targets and the source and replication clusters are in a dedicated replication         configuration. With one-to-one replication, you can configure multiple replication pairs,         but a source cluster can replicate to a maximum of two target clusters.<\/p>","href":"saas\/rsc_creating_sla_domains_onetoone_rep_2.html","attributes":{"data-id":"rsc_creating_sla_domains_onetoone_rep"},"menu":{"hasChildren":false},"tocID":"rsc_creating_sla_domains_onetoone_rep-d30753e26215","topics":[]},{"title":"Assigning an SLA Domain to Proxmox virtual machines","shortdesc":"<p class=\"shortdesc\">Assign an SLA Domain to protect Proxmox virtual machines and define their backup         frequency and their retention policies.<\/p>","href":"proxmox\/assigning_sla_domain_proxmox_vms.html","attributes":{"data-id":"assigning_sla_domain_proxmox_vms"},"menu":{"hasChildren":false},"tocID":"assigning_sla_domain_proxmox_vms-d30753e26226","topics":[]},{"title":"Assigning an SLA Domain to Proxmox clusters","shortdesc":"<p class=\"shortdesc\">Assign an SLA Domain to protect a Proxmox cluster and define its backup frequency and         their retention policies.<\/p>","href":"proxmox\/assigning_sla_domain_proxmox_clusters.html","attributes":{"data-id":"assigning_sla_domain_proxmox_clusters"},"menu":{"hasChildren":false},"tocID":"assigning_sla_domain_proxmox_clusters-d30753e26237","topics":[]},{"title":"Assigning an SLA Domain to Proxmox nodes","shortdesc":"<p class=\"shortdesc\">Assign an SLA Domain to protect Proxmox nodes and define their backup frequency and         retention policies.<\/p>","href":"proxmox\/assigning_sla_domain_proxmox_nodes.html","attributes":{"data-id":"assigning_sla_domain_proxmox_nodes"},"menu":{"hasChildren":false},"tocID":"assigning_sla_domain_proxmox_nodes-d30753e26248","topics":[]}]}};